<?php get_header(); while(have_posts()): the_post(); $label = get_post_meta(get_the_ID(), '_casa_button_label', true) ?: 'Solicitar información'; $url = get_post_meta(get_the_ID(), '_casa_button_url', true) ?: 'https://www.instagram.com/casa.messer/'; ?><main><section class="detail-hero"><div><p class="eyebrow">CASA MESSER</p><h1><?php the_title(); ?></h1></div><?php if(has_post_thumbnail()): the_post_thumbnail('large'); else: ?><img src="<?php echo esc_url(casa_messer_fallback_image(0)); ?>" alt="<?php the_title_attribute(); ?>"><?php endif; ?></section><article class="entry"><?php the_content(); ?><a class="button" href="<?php echo esc_url($url); ?>"><?php echo esc_html($label); ?> ↗</a></article></main><?php endwhile; get_footer(); ?>
